 1	import React, { FC } from 'react';
 2	
 3	import {
 4	  V1VirtualMachineInstance,
 5	  V1VirtualMachineInstanceGuestAgentInfo,
 6	  V1VirtualMachineInstanceGuestOSUser,
 7	} from '@kubevirt-ui/kubevirt-api/kubevirt';
 8	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
10	import { isGuestAgentConnected } from '@kubevirt-utils/resources/vmi';
11	import { VirtualizedTable } from '@openshift-console/dynamic-plugin-sdk';
12	import { Bullseye, Card, CardBody, CardTitle, Divider } from '@patternfly/react-core';
13	
14	import useActiveUsersColumnsVm from './hooks/useActiveUsersColumnsVm';
15	import ActiveUserListRowVm from './ActiveUserListRowVm';
16	
17	type VirtualMachinesOverviewTabActiveUserProps = {
18	  guestAgentData: V1VirtualMachineInstanceGuestAgentInfo;
19	  guestAgentDataLoaded: boolean;
20	  guestAgentDataLoadError: Error;
21	  vmi: V1VirtualMachineInstance;
22	};
23	
24	const VirtualMachinesOverviewTabActiveUser: FC<VirtualMachinesOverviewTabActiveUserProps> = ({
25	  guestAgentData,
26	  guestAgentDataLoaded,
27	  guestAgentDataLoadError,
28	  vmi,
29	}) => {
30	  const { t } = useKubevirtTranslation();
31	  const columns = useActiveUsersColumnsVm();
32	  const userList = guestAgentData?.userList || [];
33	  const bodyTable =
34	    vmi && isGuestAgentConnected(vmi) ? (
35	      <VirtualizedTable<V1VirtualMachineInstanceGuestOSUser>
36	        columns={columns}
37	        data={userList}
38	        loaded={guestAgentDataLoaded}
39	        loadError={guestAgentDataLoadError}
40	        NoDataEmptyMsg={() => <Bullseye>{t('No active users')}</Bullseye>}
41	        Row={ActiveUserListRowVm}
42	        unfilteredData={userList}
43	      />
44	    ) : (
45	      <Bullseye>
46	        <MutedTextSpan
47	          text={vmi ? t('Guest agent is required') : t('VirtualMachine is not running')}
48	        />
49	      </Bullseye>
50	    );
51	
52	  return (
53	    <Card>
54	      <CardTitle className="text-muted">
55	        {t('Active users ({{users}})', { users: userList?.length })}
56	      </CardTitle>
57	      <Divider />
58	      <CardBody isFilled>{bodyTable}</CardBody>
59	    </Card>
60	  );
61	};
62	
63	export default VirtualMachinesOverviewTabActiveUser;

